SELECT COUNT(*) AS total_episodes
FROM show_episodes
WHERE show_id = 0;

SELECT COUNT(*) AS feedback_count
FROM episode_feedback
WHERE rating > 3;

SELECT MAX(rating) AS max_rating
FROM episode_feedback
WHERE episode_id = 1;

SELECT title
FROM show_episodes
WHERE duration > 60;

SELECT show_id, user_id, edit_timestamp
FROM edit_log
WHERE edit_type = 'update';
